import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
vi.mock("../activeStudioSession.js", () => ({
    clearActiveStudioSession: vi.fn(),
    writeActiveStudioSession: vi.fn(),
}));
vi.mock("../agentSessionChannel.js", () => ({
    createAgentSession: vi.fn().mockResolvedValue({ ok: true }),
    pollAgentSessionEvents: vi.fn().mockResolvedValue(undefined),
}));
vi.mock("../browser.js", () => ({
    openChromelessWindow: vi.fn(),
}));
vi.mock("../frontmostApp.js", () => ({
    recordFocus: vi.fn(() => vi.fn()),
}));
const SESSION_ID = "11111111-1111-4111-8111-111111111111";
const SERVICE_URL = "https://test.invalid";
const API_KEY = "key-test";
function navigatedEvent(path, search, id = "evt-nav") {
    return { id, type: "studio:navigated", data: { path, search } };
}
function sessionEndedEvent(id = "evt-1") {
    return { id, type: "studio:session-ended", data: {} };
}
function sessionClosedEvent(id = "evt-1") {
    return { id, type: "studio:session-closed", data: {} };
}
function sessionStartedEvent(id = "evt-2") {
    return { id, type: "studio:session-started", data: {} };
}
describe("openStudio session lifecycle", () => {
    let pollMock;
    let clearActiveSession;
    let stdoutSpy;
    let consoleSpy;
    beforeEach(async () => {
        vi.useFakeTimers();
        vi.resetAllMocks();
        const channel = await import("../agentSessionChannel.js");
        pollMock = channel.pollAgentSessionEvents;
        channel.createAgentSession.mockResolvedValue({ ok: true });
        const active = await import("../activeStudioSession.js");
        clearActiveSession = active.clearActiveStudioSession;
        stdoutSpy = vi.spyOn(process.stdout, "write").mockReturnValue(true);
        consoleSpy = vi.spyOn(console, "error").mockImplementation(() => { });
    });
    afterEach(() => {
        vi.useRealTimers();
        vi.restoreAllMocks();
    });
    async function startStudioAndGetOnEvent() {
        let capturedOnEvent = null;
        pollMock.mockImplementation((opts) => {
            capturedOnEvent = opts.onEvent;
            return new Promise(() => { });
        });
        const { openStudio } = await import("./openStudio.js");
        const session = await openStudio({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        if (!capturedOnEvent) {
            throw new Error("pollAgentSessionEvents was not called");
        }
        return { onEvent: capturedOnEvent, session };
    }
    describe("reconnect mode", () => {
        it("skips browser open and recordFocus when reconnect is true", async () => {
            pollMock.mockImplementation(() => new Promise(() => { }));
            const { openStudio } = await import("./openStudio.js");
            const { openChromelessWindow } = await import("../browser.js");
            const { recordFocus } = await import("../frontmostApp.js");
            const session = await openStudio({
                serviceUrl: SERVICE_URL,
                apiKey: API_KEY,
                sessionId: SESSION_ID,
                reconnect: true,
            });
            expect(openChromelessWindow).not.toHaveBeenCalled();
            expect(recordFocus).not.toHaveBeenCalled();
            session.abort();
        });
        it("still creates the agent session when reconnecting", async () => {
            pollMock.mockImplementation(() => new Promise(() => { }));
            const { openStudio } = await import("./openStudio.js");
            const { createAgentSession } = await import("../agentSessionChannel.js");
            const session = await openStudio({
                serviceUrl: SERVICE_URL,
                apiKey: API_KEY,
                sessionId: SESSION_ID,
                reconnect: true,
            });
            expect(createAgentSession).toHaveBeenCalledWith(expect.objectContaining({ sessionId: SESSION_ID }));
            session.abort();
        });
        it("starts polling for events when reconnecting", async () => {
            pollMock.mockImplementation(() => new Promise(() => { }));
            const { openStudio } = await import("./openStudio.js");
            const session = await openStudio({
                serviceUrl: SERVICE_URL,
                apiKey: API_KEY,
                sessionId: SESSION_ID,
                reconnect: true,
            });
            expect(pollMock).toHaveBeenCalledWith(expect.objectContaining({ sessionId: SESSION_ID }));
            session.abort();
        });
    });
    describe("studio:navigated", () => {
        it("emits navigated event with path and search", async () => {
            const { onEvent, session } = await startStudioAndGetOnEvent();
            onEvent(navigatedEvent("/studio/datasets/abc", "?trace=t1"));
            const emitted = stdoutSpy.mock.calls.map((c) => JSON.parse(String(c[0])));
            expect(emitted).toContainEqual({
                event: "navigated",
                sessionId: SESSION_ID,
                path: "/studio/datasets/abc",
                search: "?trace=t1",
            });
            session.abort();
        });
        it("emits navigated event without search when absent", async () => {
            const { onEvent, session } = await startStudioAndGetOnEvent();
            onEvent(navigatedEvent("/studio/traces"));
            const emitted = stdoutSpy.mock.calls.map((c) => JSON.parse(String(c[0])));
            expect(emitted).toContainEqual({
                event: "navigated",
                sessionId: SESSION_ID,
                path: "/studio/traces",
                search: undefined,
            });
            session.abort();
        });
    });
    describe("studio:session-ended (explicit End Session button)", () => {
        it("aborts immediately", async () => {
            const { onEvent } = await startStudioAndGetOnEvent();
            onEvent(sessionEndedEvent());
            const emitted = stdoutSpy.mock.calls.map((c) => String(c[0]));
            expect(emitted.some((s) => s.includes("session-ended"))).toBe(true);
            expect(clearActiveSession).toHaveBeenCalledTimes(1);
        });
        it("cancels any pending session-closed grace timer", async () => {
            const { onEvent } = await startStudioAndGetOnEvent();
            onEvent(sessionClosedEvent("evt-1"));
            onEvent(sessionEndedEvent("evt-2"));
            const emitted = stdoutSpy.mock.calls.map((c) => String(c[0]));
            expect(emitted.some((s) => s.includes("session-ended"))).toBe(true);
            expect(clearActiveSession).toHaveBeenCalledTimes(1);
        });
    });
    describe("studio:session-closed (tab close / refresh)", () => {
        it("does NOT abort immediately, waits for grace period", async () => {
            const { onEvent, session } = await startStudioAndGetOnEvent();
            onEvent(sessionClosedEvent());
            const emitted = stdoutSpy.mock.calls.map((c) => String(c[0]));
            expect(emitted.some((s) => s.includes("session-ended"))).toBe(false);
            expect(clearActiveSession).not.toHaveBeenCalled();
            session.abort();
        });
        it("aborts after 10s if no session-started arrives", async () => {
            const { onEvent } = await startStudioAndGetOnEvent();
            onEvent(sessionClosedEvent());
            await vi.advanceTimersByTimeAsync(10_000);
            const emitted = stdoutSpy.mock.calls.map((c) => String(c[0]));
            expect(emitted.some((s) => s.includes("session-ended"))).toBe(true);
            expect(clearActiveSession).toHaveBeenCalledTimes(1);
        });
        it("cancels abort when session-started arrives within the grace window", async () => {
            const { onEvent, session } = await startStudioAndGetOnEvent();
            onEvent(sessionClosedEvent());
            await vi.advanceTimersByTimeAsync(5_000);
            onEvent(sessionStartedEvent());
            await vi.advanceTimersByTimeAsync(10_000);
            const emitted = stdoutSpy.mock.calls.map((c) => String(c[0]));
            expect(emitted.some((s) => s.includes("session-ended"))).toBe(false);
            expect(clearActiveSession).not.toHaveBeenCalled();
            const consoleOutput = consoleSpy.mock.calls.map((c) => String(c[0]));
            expect(consoleOutput.some((s) => s.includes("Studio reconnected"))).toBe(true);
            session.abort();
        });
        it("ignores duplicate session-closed events during the grace window", async () => {
            const { onEvent } = await startStudioAndGetOnEvent();
            onEvent(sessionClosedEvent("evt-1"));
            await vi.advanceTimersByTimeAsync(3_000);
            onEvent(sessionClosedEvent("evt-2"));
            await vi.advanceTimersByTimeAsync(7_000);
            const emitted = stdoutSpy.mock.calls.map((c) => String(c[0]));
            const endedCount = emitted.filter((s) => s.includes("session-ended")).length;
            expect(endedCount).toBe(1);
            expect(clearActiveSession).toHaveBeenCalledTimes(1);
        });
        it("handles a second session-closed after a session-started cancellation", async () => {
            const { onEvent } = await startStudioAndGetOnEvent();
            onEvent(sessionClosedEvent("evt-1"));
            await vi.advanceTimersByTimeAsync(3_000);
            onEvent(sessionStartedEvent("evt-2"));
            onEvent(sessionClosedEvent("evt-3"));
            await vi.advanceTimersByTimeAsync(10_000);
            const emitted = stdoutSpy.mock.calls.map((c) => String(c[0]));
            expect(emitted.some((s) => s.includes("session-ended"))).toBe(true);
            expect(clearActiveSession).toHaveBeenCalledTimes(1);
        });
    });
});
